import { ref, computed } from 'vue'
import type { ServiceConfig } from '~/types'

const STORAGE_KEY = 'status-dashboard-services'

const services = ref<ServiceConfig[]>([])

function load() {
  if (!import.meta.client) return
  try {
    const raw = localStorage.getItem(STORAGE_KEY)
    services.value = raw ? JSON.parse(raw) : []
  }
  catch {
    services.value = []
  }
}

function save() {
  if (!import.meta.client) return
  localStorage.setItem(STORAGE_KEY, JSON.stringify(services.value))
}

function addService(config: Omit<ServiceConfig, 'id' | 'createdAt'>) {
  const service: ServiceConfig = {
    ...config,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
  }
  services.value.push(service)
  save()
  return service
}

function updateService(id: string, updates: Partial<Omit<ServiceConfig, 'id' | 'createdAt'>>) {
  const idx = services.value.findIndex((s) => s.id === id)
  if (idx === -1) return
  services.value[idx] = { ...services.value[idx], ...updates }
  save()
}

function removeService(id: string) {
  services.value = services.value.filter((s) => s.id !== id)
  save()
}

function toggleService(id: string) {
  const svc = services.value.find((s) => s.id === id)
  if (svc) updateService(id, { enabled: !svc.enabled })
}

export function useServices() {
  if (import.meta.client && services.value.length === 0) {
    load()
  }

  return {
    services: computed(() => services.value),
    enabledServices: computed(() => services.value.filter((s) => s.enabled)),
    addService,
    updateService,
    removeService,
    toggleService,
    reload: load,
  }
}
