export type StatusLevel = 'operational' | 'leger' | 'mineur' | 'majeur' | 'maintenance'

export type HttpMethod = 'GET' | 'POST'

export interface ServiceConfig {
  id: string
  name: string
  url: string
  method: HttpMethod
  headers: Record<string, string>
  body?: string
  adapter: string
  group?: string
  pollInterval: number // secondes, max 120
  enabled: boolean
  createdAt: string
}

export interface Incident {
  id: string
  title: string
  level: StatusLevel
  startedAt: string
  updatedAt: string
  message?: string
  url?: string
}

export interface StatusSnapshot {
  serviceId: string
  timestamp: string
  level: StatusLevel
  message: string
  incidents: Incident[]
}

export interface AdapterResult {
  level: StatusLevel
  message: string
  incidents: Incident[]
}

